import { useState, useEffect, useRef } from "react";
import { useNavigate } from "react-router-dom";
import beautyImg from "../assets/Beauty.png";
import clothingImg from "../assets/Clothing.png";
import ElectImg from "../assets/Electronics.png";
import furniImg from "../assets/Furniture.png";
import hdImg from "../assets/Homedecor.png"; 
import all from "../assets/All.png";
import boatImg from "../assets/boat.png";
import maxImg from "../assets/max.png";
import lakmeImg from "../assets/lakme.png";
import homeImg from "../assets/splhome.png";

function getUserName() {
  try { return localStorage.getItem("username") || "User"; } catch { return "User"; }
}

// ─── Clean, high-quality SVG icon components ─────────────────────────────────
const Icon = ({ size = 20, stroke = "currentColor", strokeWidth = 1.8, fill = "none", children, style }) => (
  <svg
    width={size} height={size}
    viewBox="0 0 24 24"
    fill={fill}
    stroke={stroke}
    strokeWidth={strokeWidth}
    strokeLinecap="round"
    strokeLinejoin="round"
    style={{ display: "block", flexShrink: 0, ...style }}
  >
    {children}
  </svg>
);

const MenuIcon = (p) => (
  <Icon {...p}>
    <line x1="3" y1="6" x2="21" y2="6" />
    <line x1="3" y1="12" x2="21" y2="12" />
    <line x1="3" y1="18" x2="21" y2="18" />
  </Icon>
);

const CloseIcon = (p) => (
  <Icon {...p}>
    <line x1="18" y1="6" x2="6" y2="18" />
    <line x1="6" y1="6" x2="18" y2="18" />
  </Icon>
);

const SearchIcon = (p) => (
  <Icon {...p}>
    <circle cx="11" cy="11" r="8" />
    <line x1="21" y1="21" x2="16.65" y2="16.65" />
  </Icon>
);

const ChevronDown = (p) => (
  <Icon {...p}>
    <polyline points="6 9 12 15 18 9" />
  </Icon>
);

const ChevronRight = (p) => (
  <Icon {...p}>
    <polyline points="9 18 15 12 9 6" />
  </Icon>
);

const UserIcon = (p) => (
  <Icon {...p}>
    <path d="M20 21v-2a4 4 0 0 0-4-4H8a4 4 0 0 0-4 4v2" />
    <circle cx="12" cy="7" r="4" />
  </Icon>
);

const OrdersIcon = (p) => (
  <Icon {...p}>
    <path d="M14 2H6a2 2 0 0 0-2 2v16a2 2 0 0 0 2 2h12a2 2 0 0 0 2-2V8z" />
    <polyline points="14 2 14 8 20 8" />
    <line x1="16" y1="13" x2="8" y2="13" />
    <line x1="16" y1="17" x2="8" y2="17" />
    <polyline points="10 9 9 9 8 9" />
  </Icon>
);

const WalletIcon = (p) => (
  <Icon {...p}>
    <rect x="1" y="4" width="22" height="16" rx="2" ry="2" />
    <line x1="1" y1="10" x2="23" y2="10" />
  </Icon>
);

const BellIcon = (p) => (
  <Icon {...p}>
    <path d="M18 8A6 6 0 0 0 6 8c0 7-3 9-3 9h18s-3-2-3-9" />
    <path d="M13.73 21a2 2 0 0 1-3.46 0" />
  </Icon>
);

const SignOutIcon = (p) => (
  <Icon {...p}>
    <path d="M9 21H5a2 2 0 0 1-2-2V5a2 2 0 0 1 2-2h4" />
    <polyline points="16 17 21 12 16 7" />
    <line x1="21" y1="12" x2="9" y2="12" />
  </Icon>
);

const HeartIcon = (p) => (
  <Icon {...p}>
    <path d="M20.84 4.61a5.5 5.5 0 0 0-7.78 0L12 5.67l-1.06-1.06a5.5 5.5 0 0 0-7.78 7.78l1.06 1.06L12 21.23l7.78-7.78 1.06-1.06a5.5 5.5 0 0 0 0-7.78z" />
  </Icon>
);

const CartIcon = (p) => (
  <Icon {...p}>
    <circle cx="9" cy="21" r="1" />
    <circle cx="20" cy="21" r="1" />
    <path d="M1 1h4l2.68 13.39a2 2 0 0 0 2 1.61h9.72a2 2 0 0 0 2-1.61L23 6H6" />
  </Icon>
);

const ShoppingBagIcon = (p) => (
  <Icon {...p}>
    <path d="M6 2L3 6v14a2 2 0 0 0 2 2h14a2 2 0 0 0 2-2V6l-3-4z" />
    <line x1="3" y1="6" x2="21" y2="6" />
    <path d="M16 10a4 4 0 0 1-8 0" />
  </Icon>
);

const TruckIcon = (p) => (
  <Icon {...p}>
    <rect x="1" y="3" width="15" height="13" rx="1" />
    <path d="M16 8h4l3 5v4h-7V8z" />
    <circle cx="5.5" cy="18.5" r="2.5" />
    <circle cx="18.5" cy="18.5" r="2.5" />
  </Icon>
);

const RefreshIcon = (p) => (
  <Icon {...p}>
    <polyline points="23 4 23 10 17 10" />
    <polyline points="1 20 1 14 7 14" />
    <path d="M3.51 9a9 9 0 0 1 14.85-3.36L23 10M1 14l4.64 4.36A9 9 0 0 0 20.49 15" />
  </Icon>
);

const LockIcon = (p) => (
  <Icon {...p}>
    <rect x="3" y="11" width="18" height="11" rx="2" ry="2" />
    <path d="M7 11V7a5 5 0 0 1 10 0v4" />
  </Icon>
);

const BadgeCheckIcon = (p) => (
  <Icon {...p}>
    <path d="M12 2l2.4 4.8L20 8l-4 4.4.8 5.6L12 15l-4.8 3 .8-5.6L4 8l5.6-1.2L12 2z" />
    <polyline points="9 12 11 14 15 10" />
  </Icon>
);

const MailIcon = (p) => (
  <Icon {...p}>
    <path d="M4 4h16c1.1 0 2 .9 2 2v12c0 1.1-.9 2-2 2H4c-1.1 0-2-.9-2-2V6c0-1.1.9-2 2-2z" />
    <polyline points="22,6 12,13 2,6" />
  </Icon>
);

// Social icons as simple lettered SVGs with proper text centering
const SocialIcon = ({ letter }) => (
  <svg width="30" height="30" viewBox="0 0 30 30" fill="none" style={{ display: "block" }}>
    <circle cx="15" cy="15" r="15" fill="rgba(255,255,255,0.08)" />
    <text x="15" y="15" textAnchor="middle" dominantBaseline="central"
      fontSize="11" fontWeight="700" fill="rgba(255,255,255,0.5)"
      fontFamily="DM Sans, system-ui, sans-serif">
      {letter}
    </text>
  </svg>
);

// ─── Data ─────────────────────────────────────────────────────────────────────
const menuItems = {
  Information: [
    { name: "About Us", href: "/about" },
    { name: "Contact", href: "/contact" },
    { name: "FAQs", href: "/faqs" },
    { name: "Help & Support", href: "/help" },
  ],
  Legal: [
    { name: "Privacy Policy", href: "/privacy" },
    { name: "Terms & Conditions", href: "/terms" },
    { name: "Refund & Return Policy", href: "/refund" },
    { name: "Shipping Policy", href: "/shipping" },
  ],
};

const categories = [
 { name:"All", slug:"all", img: all },
{ name:"Clothing", slug:"clothing", img:clothingImg },
 { name:"Electronics", slug:"electronics", img:ElectImg },
 { name:"Beauty", slug:"beauty", img:beautyImg },
 { name:"Home Decor", slug:"homedecor", img:hdImg },
 { name:"Furniture", slug:"furniture", img:furniImg }
];

const banners = [
  { img: "data:image/jpeg;base64," },
  { img: "data:image/jpeg;base64," },
  { img: "data:image/jpeg;base64," },
];

const trustBadges = [
  { Icon: TruckIcon,      title: "Free Delivery",    sub: "Orders above ₹499" },
  { Icon: RefreshIcon,    title: "Easy Returns",     sub: "10-day hassle-free" },
  { Icon: LockIcon,       title: "Secure Payments",  sub: "100% encrypted" },
  { Icon: BadgeCheckIcon, title: "Genuine Products", sub: "Verified dealers only" },
];

const curated = [
  {
    tag: "Flash Deal",
    heading: "Boat",
    sub: "Premium tech at unbeatable prices",
    img: require("../assets/boat.png"),
    cta: "Shop Electronics",
    accent: "#0ea5e9",
  },
  {
    tag: "New In",
    heading: "MAX",
    sub: "Latest trends for every occasion",
    img: require("../assets/max.png"),
    cta: "Explore Fashion",
    accent: "#f43f5e",
    imgPos: "top center",
  },
  {
    tag: "Best Sellers",
    heading: "Lakme",
    sub: "Top-rated Iconic cosmetics",
    img: require("../assets/lakme.png"),
    cta: "View Beauty",
    accent: "#a855f7",
  },
  {
    tag: "Editor's Pick",
    heading: "Home Center",
    sub: "Elevate every corner of your home",
    img: require("../assets/splhome.png"),
    cta: "Discover Home",
    accent: "#10b981",
  },
];

const stats = [
  { value: "2M+",   label: "Happy Customers" },
  { value: "500K+", label: "Products Listed" },
  { value: "98%",   label: "Satisfaction Rate" },
  { value: "24/7",  label: "Customer Support" },
];
const dropdownItems = [
  { label: "My Orders",     IconComp: OrdersIcon },
  { label: "My Wallet",     IconComp: WalletIcon },
];
// ─── Component ────────────────────────────────────────────────────────────────
export default function InstaBuyHome() {
    const navigate = useNavigate();
  const [isMenuOpen, setIsMenuOpen] = useState(false);
  const [isUserDropdownOpen, setIsUserDropdownOpen] = useState(false);
  const [searchQuery, setSearchQuery] = useState("");
  const [activeCategory, setActiveCategory] = useState("All");
  const [bannerIndex, setBannerIndex] = useState(0);
  const [cartFlash, setCartFlash] = useState(false);
  const dropdownRef = useRef(null);
  const userName = getUserName();
  const routes = {
    "My Orders":     "/myorders",
    "My Wallet":     "/mywallet",
  };

  useEffect(() => {
    const t = setInterval(() => setBannerIndex(i => (i + 1) % banners.length), 5000);
    return () => clearInterval(t);
  }, []);

  useEffect(() => {
    const handleClick = (e) => {
      if (dropdownRef.current && !dropdownRef.current.contains(e.target)) setIsUserDropdownOpen(false);
      if (!e.target.closest(".sidebar-menu") && !e.target.closest(".menu-btn")) setIsMenuOpen(false);
    };
    document.addEventListener("mousedown", handleClick);
    return () => document.removeEventListener("mousedown", handleClick);
  }, []);

  const addToCart = () => { setCartFlash(true); setTimeout(() => setCartFlash(false), 400); };
  const banner = banners[bannerIndex];

  return (
    <>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=DM+Serif+Display:ital@0;1&family=DM+Sans:wght@300;400;500;600;700&display=swap');
        *{box-sizing:border-box;margin:0;padding:0;}
        :root{
          --orange:#f97316;
          --orange-deep:#ea580c;
          --orange-pale:#fff7ed;
          --ink:#0f0e0d;
          --ink-60:rgba(15,14,13,0.6);
          --ink-30:rgba(15,14,13,0.3);
          --border:#e8e4df;
          --surface:#faf9f7;
          --white:#ffffff;
          --serif:'DM Serif Display',Georgia,serif;
          --sans:'DM Sans',system-ui,sans-serif;
          --radius:14px;
          --shadow-sm:0 1px 4px rgba(0,0,0,0.06);
          --shadow-md:0 4px 20px rgba(0,0,0,0.08);
          --shadow-lg:0 12px 48px rgba(0,0,0,0.12);
        }
        html{scroll-behavior:smooth;}
        body{font-family:var(--sans);background:var(--surface);color:var(--ink);}
        ::-webkit-scrollbar{width:6px;height:6px;}
        ::-webkit-scrollbar-track{background:transparent;}
        ::-webkit-scrollbar-thumb{background:#e0d9d1;border-radius:3px;}
        .sidebar-menu::-webkit-scrollbar{display:none;}
        .cat-strip::-webkit-scrollbar{display:none;}
        .dd-item:hover{background:#fff7ed!important;color:#f97316!important;}
        .dd-item:hover svg{stroke:#f97316!important;}
        .sb-link:hover{background:#fff7ed!important;color:#f97316!important;}
        .banner-btn:hover{background:#ea580c!important;transform:translateY(-1px);}
        .curated-card:hover .curated-img{transform:scale(1.04);}
        .curated-card:hover{box-shadow:0 20px 60px rgba(0,0,0,0.14)!important;transform:translateY(-3px);}
        .ft-link:hover{color:#f97316!important;}
        .trust-item:hover{background:var(--orange-pale)!important;}
        .search-input:focus{border-color:#f97316!important;box-shadow:0 0 0 3px rgba(249,115,22,0.12)!important;background:#fff!important;}
        .header-btn:hover{background:var(--orange-pale)!important;}
        @keyframes fadeUp{from{opacity:0;transform:translateY(16px);}to{opacity:1;transform:translateY(0);}}
        .fade-up{animation:fadeUp 0.5s ease both;}
        .fade-up-1{animation-delay:0.05s;}
        .fade-up-2{animation-delay:0.12s;}
        .fade-up-3{animation-delay:0.19s;}
        .fade-up-4{animation-delay:0.26s;}
        @keyframes bannerIn{from{opacity:0;transform:translateX(-18px);}to{opacity:1;transform:none;}}
        .banner-content{animation:bannerIn 0.55s cubic-bezier(0.22,1,0.36,1);}
        @keyframes cartPop{0%,100%{transform:scale(1);}50%{transform:scale(1.35);}}
        .cart-pop{animation:cartPop 0.3s ease;}
        .social-btn:hover circle{fill:#f97316!important;}
        .social-btn:hover text{fill:white!important;}
      `}</style>

      <div style={{minHeight:"100vh",background:"var(--surface)",fontFamily:"var(--sans)"}}>

        {/* ══════════ HEADER ══════════ */}
        <header style={{
          position:"sticky",top:0,zIndex:50,
          background:"rgba(255,255,255,0.96)",
          backdropFilter:"blur(12px)",
          borderBottom:"1px solid var(--border)",
          boxShadow:"var(--shadow-sm)",
        }}>
          <div style={{background:"var(--ink)",padding:"6px 1.5rem",textAlign:"center"}}>
            <span style={{fontSize:12,color:"rgba(255,255,255,0.75)",letterSpacing:"0.04em"}}>
              Free delivery on orders above ₹499 &nbsp;·&nbsp; Use code&nbsp;
              <strong style={{color:"#f97316",letterSpacing:"0.06em"}}>FIRST10</strong>
              &nbsp;for 10% off your first order
            </span>
          </div>

          <div style={{maxWidth:1340,margin:"0 auto",padding:"0 1.5rem",display:"flex",alignItems:"center",height:62,gap:"1rem"}}>
            {/* Left */}
            <div style={{display:"flex",alignItems:"center",gap:12,flexShrink:0}}>
              <button className="menu-btn" onClick={() => setIsMenuOpen(o => !o)}
                style={{background:"transparent",border:"none",cursor:"pointer",padding:"6px",borderRadius:8,display:"flex",alignItems:"center",justifyContent:"center",color:"var(--ink)"}}>
                {isMenuOpen
                  ? <CloseIcon size={20} stroke="var(--ink)" strokeWidth={2.2} />
                  : <MenuIcon  size={20} stroke="var(--ink)" strokeWidth={2.2} />
                }
              </button>

              {/* Logo */}
              <div style={{display:"flex",alignItems:"center",gap:8}}>
                <div style={{width:34,height:34,borderRadius:10,background:"linear-gradient(135deg,#f97316,#ea580c)",display:"flex",alignItems:"center",justifyContent:"center",boxShadow:"0 3px 10px rgba(249,115,22,0.35)"}}>
                  <ShoppingBagIcon size={17} stroke="white" strokeWidth={2.3} />
                </div>
                <span style={{fontFamily:"var(--serif)",fontSize:"1.25rem",fontWeight:400,color:"var(--ink)",letterSpacing:"-0.01em"}}>InstaBuy</span>
              </div>
            </div>

            {/* Right */}
            <div style={{display:"flex",alignItems:"center",gap:2,flexShrink:0,marginLeft:"auto"}}>
              {/* User dropdown */}
              <div style={{position:"relative"}} ref={dropdownRef}>
                <button
                  className="header-btn"
                  onClick={() => setIsUserDropdownOpen(o => !o)}
                  style={{display:"flex",alignItems:"center",gap:7,background:"transparent",border:"none",borderRadius:10,cursor:"pointer",padding:"6px 10px",transition:"background 0.18s"}}>
                  <div style={{width:30,height:30,borderRadius:"50%",background:"linear-gradient(135deg,#f97316,#ea580c)",display:"flex",alignItems:"center",justifyContent:"center"}}>
                    <span style={{fontSize:12,fontWeight:700,color:"white"}}>{userName.charAt(0).toUpperCase()}</span>
                  </div>
                  <div style={{display:"flex",flexDirection:"column",alignItems:"flex-start",lineHeight:1.2}}>
                    <span style={{fontSize:10,color:"var(--ink-60)",fontWeight:400}}>Hello,</span>
                    <span style={{fontSize:12,color:"var(--ink)",fontWeight:700,maxWidth:68,overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{userName}</span>
                  </div>
                  <ChevronDown size={12} stroke="var(--ink-60)" strokeWidth={2.5} />
                </button>

                {isUserDropdownOpen && (
                  <div style={{
                    position:"absolute",top:"calc(100% + 10px)",right:0,
                    background:"white",border:"1px solid var(--border)",
                    borderRadius:16,boxShadow:"var(--shadow-lg)",
                    minWidth:210,zIndex:100,overflow:"hidden",
                  }}>
                    <div style={{padding:"14px 16px",display:"flex",alignItems:"center",gap:10,background:"var(--orange-pale)"}}>
                      <div style={{width:36,height:36,borderRadius:"50%",background:"linear-gradient(135deg,#f97316,#ea580c)",display:"flex",alignItems:"center",justifyContent:"center",fontSize:15,fontWeight:700,color:"white",flexShrink:0}}>
                        {userName.charAt(0).toUpperCase()}
                      </div>
                      <div>
                        <div style={{fontSize:13,fontWeight:700,color:"var(--ink)"}}>{userName}</div>
                        <div style={{fontSize:11,color:"var(--ink-60)"}}>Member</div>
                      </div>
                    </div>
                    <div style={{height:1,background:"var(--border)"}}/>
                    {dropdownItems.map(({ label, IconComp }) => (
  <button key={label} className="dd-item"
    style={{display:"flex",alignItems:"center",gap:10,width:"100%",padding:"10px 16px",background:"transparent",border:"none",cursor:"pointer",fontSize:13,fontWeight:500,color:"var(--ink)",textAlign:"left",transition:"all 0.15s"}}
    onClick={() => { setIsUserDropdownOpen(false); navigate(routes[label]); }}>
    <IconComp size={15} stroke="#f97316" strokeWidth={2} />
    {label}
  </button>
))}
                    <div style={{height:1,background:"var(--border)"}}/>
                    <button className="dd-item"
                      style={{display:"flex",alignItems:"center",gap:10,width:"100%",padding:"10px 16px",background:"transparent",border:"none",cursor:"pointer",fontSize:13,fontWeight:500,color:"#dc2626",textAlign:"left",transition:"all 0.15s"}}
                      onClick={() => { try { localStorage.clear(); } catch{} window.location.href="/login"; }}>
                      <SignOutIcon size={15} stroke="#dc2626" strokeWidth={2} />
                      Sign Out
                    </button>
                  </div>
                )}
              </div>

              {/* Cart */}
              <button
                className="header-btn"
                onClick={addToCart}
                style={{display:"flex",alignItems:"center",gap:6,background:cartFlash?"var(--orange-pale)":"transparent",border:"none",borderRadius:10,cursor:"pointer",padding:"6px 12px",transition:"background 0.2s"}}>
                <span className={cartFlash ? "cart-pop" : ""} style={{display:"flex"}}>
                  <CartIcon size={20} stroke="var(--ink)" strokeWidth={1.8} />
                </span>
                <span style={{fontSize:12,fontWeight:600,color:"var(--ink)"}}>Cart</span>
              </button>
            </div>
          </div>
        </header>

        {/* ══════════ SIDEBAR ══════════ */}
        <div className="sidebar-menu" style={{
          position:"fixed",top:0,left:0,width:290,height:"100vh",
          background:"white",borderRight:"1px solid var(--border)",
          boxShadow:"12px 0 40px rgba(0,0,0,0.08)",zIndex:200,
          transition:"transform 0.32s cubic-bezier(0.4,0,0.2,1)",
          overflowY:"auto",paddingTop:72,
          transform: isMenuOpen ? "translateX(0)" : "translateX(-100%)",
        }}>
          <div style={{padding:"1.5rem"}}>
            <div style={{display:"flex",alignItems:"center",gap:10,marginBottom:"1.8rem",padding:"12px 14px",background:"var(--orange-pale)",borderRadius:12,border:"1px solid #fed7aa"}}>
              <div style={{width:36,height:36,borderRadius:"50%",background:"linear-gradient(135deg,#f97316,#ea580c)",display:"flex",alignItems:"center",justifyContent:"center",flexShrink:0}}>
                <span style={{fontSize:15,fontWeight:700,color:"white"}}>{userName.charAt(0).toUpperCase()}</span>
              </div>
              <div>
                <div style={{fontSize:13,fontWeight:700,color:"var(--ink)"}}>{userName}</div>
                <div style={{fontSize:11,color:"#f97316",fontWeight:600}}>View Profile →</div>
              </div>
            </div>

            {Object.entries(menuItems).map(([cat, items]) => (
              <div key={cat} style={{marginBottom:"1.5rem"}}>
                <p style={{fontSize:10,fontWeight:700,textTransform:"uppercase",letterSpacing:"0.12em",color:"var(--ink-30)",marginBottom:8,paddingLeft:4}}>{cat}</p>
                {items.map(item => (
                  <a key={item.name} href={item.href} className="sb-link"
                    onClick={() => setIsMenuOpen(false)}
                    style={{display:"flex",alignItems:"center",justifyContent:"space-between",padding:"10px 12px",borderRadius:9,color:"var(--ink)",textDecoration:"none",fontSize:13,fontWeight:500,transition:"all 0.15s",marginBottom:2}}>
                    {item.name}
                    <ChevronRight size={13} stroke="currentColor" strokeWidth={2.5} />
                  </a>
                ))}
              </div>
            ))}
          </div>
        </div>
        {isMenuOpen && <div style={{position:"fixed",inset:0,background:"rgba(0,0,0,0.28)",zIndex:199,backdropFilter:"blur(3px)"}} onClick={() => setIsMenuOpen(false)}/>}

        {/* ══════════ MAIN ══════════ */}
        <main style={{maxWidth:1340,margin:"0 auto",padding:"0 1.5rem 4rem"}}>

          {/* ── Category Strip ── */}
          <div className="cat-strip" style={{
            display:"flex",overflowX:"auto",
            justifyContent:"center",
            borderBottom:"1px solid var(--border)",
            padding:"10px 0 0",
            background:"white",
            marginBottom:0,gap:0,
            scrollbarWidth:"none",
          }}>
            {categories.map(({ name, img ,slug}) => {
              const active = activeCategory === name;
              return (
                <button key={name} onClick={() => {
 setActiveCategory(name);
   if(name==="All"){
      navigate("/home"); // stays on home page
      return;
   }

 if(name==="Clothing"){
   navigate("/category/clothing");
 }

 if(name==="Electronics"){
   navigate("/category/electronics");
 }

 if(name==="Beauty"){
   navigate("/category/beauty");
 }

 if(name==="Home Decor"){
   navigate("/category/home-decor");
 }

 if(name==="Furniture"){
   navigate("/category/furniture");
 }
}} style={{
                  display:"flex",flexDirection:"column",alignItems:"center",gap:5,
                  padding:"6px 14px 12px",background:"transparent",border:"none",
                  cursor:"pointer",position:"relative",flexShrink:0,minWidth:88,
                  color: active ? "#f97316" : "var(--ink-60)",
                  transition:"color 0.2s",
                }}>
                  <div style={{
                    width:68,height:68,borderRadius:"50%",overflow:"hidden",
                    outline: active ? "2.5px solid #f97316" : "2.5px solid transparent",
                    outlineOffset:3,
                    transform: active ? "translateY(-2px) scale(1.06)" : "none",
                    boxShadow: active ? "0 4px 14px rgba(249,115,22,0.3)" : "0 1px 6px rgba(0,0,0,0.09)",
                    transition:"all 0.22s",
                  }}>
                    <img
                      src={img}
                      alt={name}
                      style={{
                        width:"100%",height:"100%",
                        objectFit:"cover",
                        objectPosition: name === "Beauty" ? "center 30%" : "center center",
                        borderRadius:"50%",display:"block",
                      }}
                    />
                  </div>
                  <span style={{fontSize:11,fontWeight:active?700:500,whiteSpace:"nowrap"}}>{name}</span>
                  {active && <div style={{position:"absolute",bottom:0,left:"50%",transform:"translateX(-50%)",width:"50%",height:2.5,background:"#f97316",borderRadius:2}}/>}
                </button>
              );
            })}
          </div>

          {/* ── Hero Banner ── */}
          <div style={{
            position:"relative",
            width:"100%",
            maxWidth:1100,
            margin:"1.4rem auto 0",
            borderRadius:18,
            overflow:"hidden",
            background:"#000",
            boxShadow:"var(--shadow-lg)",
          }}>
            {/* Slides */}
            <div style={{
              display:"flex",
              width:`${banners.length * 100}%`,
              transform:`translateX(-${bannerIndex * (100 / banners.length)}%)`,
              transition:"transform 0.6s cubic-bezier(0.77,0,0.18,1)",
            }}>
              {banners.map((b, i) => (
                <div key={i} style={{
                  width:`${100 / banners.length}%`,
                  flexShrink:0,
                  aspectRatio:"1400/500",
                  lineHeight:0,
                }}>
                  <img
                    src={b.img}
                    alt={`Banner ${i+1}`}
                    style={{
                      width:"100%",
                      height:"100%",
                      objectFit:"cover",
                      objectPosition:"center",
                      display:"block",
                    }}
                  />
                </div>
              ))}
            </div>

            {/* Left Arrow */}
            <button onClick={() => setBannerIndex(i => (i - 1 + banners.length) % banners.length)}
              style={{
                position:"absolute",left:16,top:"50%",transform:"translateY(-50%)",
                width:40,height:40,borderRadius:"50%",
                background:"rgba(255,255,255,0.88)",
                border:"none",cursor:"pointer",
                display:"flex",alignItems:"center",justifyContent:"center",
                boxShadow:"0 2px 12px rgba(0,0,0,0.18)",
                zIndex:10,transition:"all 0.18s",
              }}
              onMouseEnter={e => e.currentTarget.style.background="white"}
              onMouseLeave={e => e.currentTarget.style.background="rgba(255,255,255,0.88)"}
            >
              <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="#333" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round">
                <polyline points="15 18 9 12 15 6"/>
              </svg>
            </button>

            {/* Right Arrow */}
            <button onClick={() => setBannerIndex(i => (i + 1) % banners.length)}
              style={{
                position:"absolute",right:16,top:"50%",transform:"translateY(-50%)",
                width:40,height:40,borderRadius:"50%",
                background:"rgba(255,255,255,0.88)",
                border:"none",cursor:"pointer",
                display:"flex",alignItems:"center",justifyContent:"center",
                boxShadow:"0 2px 12px rgba(0,0,0,0.18)",
                zIndex:10,transition:"all 0.18s",
              }}
              onMouseEnter={e => e.currentTarget.style.background="white"}
              onMouseLeave={e => e.currentTarget.style.background="rgba(255,255,255,0.88)"}
            >
              <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="#333" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round">
                <polyline points="9 18 15 12 9 6"/>
              </svg>
            </button>

            {/* Dots */}
            <div style={{
              position:"absolute",bottom:14,left:"50%",transform:"translateX(-50%)",
              display:"flex",gap:7,zIndex:10,
            }}>
              {banners.map((_, i) => (
                <button key={i} onClick={() => setBannerIndex(i)} style={{
                  width: i===bannerIndex ? 28 : 8,
                  height:8,borderRadius:4,border:"none",cursor:"pointer",
                  background: i===bannerIndex ? "#f97316" : "rgba(255,255,255,0.65)",
                  transition:"all 0.3s",padding:0,
                }}/>
              ))}
            </div>
          </div>

                    {/* ── Trust Strip ── */}
          <div style={{
            display:"grid",gridTemplateColumns:"repeat(4,1fr)",
            gap:1,background:"var(--border)",
            borderRadius:14,overflow:"hidden",
            margin:"1.4rem 0 2rem",
            border:"1px solid var(--border)",
          }}>
            {trustBadges.map((b, i) => (
              <div key={i} className="trust-item" style={{
                display:"flex",alignItems:"center",gap:14,
                padding:"18px 20px",background:"white",
                transition:"background 0.18s",cursor:"default",
              }}>
                <div style={{
                  width:42,height:42,borderRadius:12,
                  background:"var(--orange-pale)",
                  display:"flex",alignItems:"center",justifyContent:"center",
                  flexShrink:0,
                }}>
                  <b.Icon size={20} stroke="#f97316" strokeWidth={1.8} />
                </div>
                <div>
                  <div style={{fontSize:13,fontWeight:700,color:"var(--ink)",marginBottom:2}}>{b.title}</div>
                  <div style={{fontSize:11.5,color:"var(--ink-60)"}}>{b.sub}</div>
                </div>
              </div>
            ))}
          </div>

          {/* ── Curated Collections ── */}
          <section style={{marginBottom:"2.5rem"}}>
            <div style={{display:"flex",alignItems:"baseline",justifyContent:"space-between",marginBottom:"1.2rem"}}>
              <div>
                <h2 style={{fontFamily:"var(--serif)",fontSize:"1.6rem",fontWeight:400,color:"var(--ink)",letterSpacing:"-0.02em"}}>
                  Top Brands On Deal
                </h2>
                <p style={{fontSize:13,color:"var(--ink-60)",marginTop:2}}>Hand-picked categories just for you</p>
              </div>
              <button style={{fontSize:13,fontWeight:600,color:"#f97316",background:"transparent",border:"1px solid #f97316",borderRadius:8,padding:"7px 16px",cursor:"pointer",transition:"all 0.18s",letterSpacing:"0.01em"}}
                onMouseEnter={e => { e.currentTarget.style.background="#f97316"; e.currentTarget.style.color="white"; }}
                onMouseLeave={e => { e.currentTarget.style.background="transparent"; e.currentTarget.style.color="#f97316"; }}>
                All Collections →
              </button>
            </div>

            <div style={{display:"grid",gridTemplateColumns:"repeat(auto-fill,minmax(280px,1fr))",gap:"1.2rem"}}>
              {curated.map((c, i) => (
                <div key={i} className={`curated-card fade-up fade-up-${i+1}`} style={{
                  borderRadius:16,overflow:"hidden",
                  background:"var(--ink)",
                  boxShadow:"var(--shadow-md)",
                  cursor:"pointer",
                  transition:"all 0.28s cubic-bezier(0.22,1,0.36,1)",
                  position:"relative",
                }}>
                  <div style={{height:260,overflow:"hidden",position:"relative"}}>
                    <img className="curated-img" src={c.img} alt={c.heading} style={{
                      width:"100%",height:"100%",objectFit:"cover",
                      objectPosition: c.imgPos || "center",
                      display:"block",
                      transition:"transform 0.38s cubic-bezier(0.22,1,0.36,1)",
                    }}/>
                    <div style={{
                      position:"absolute",inset:0,
                      background:"linear-gradient(to top,rgba(0,0,0,0.75) 0%,rgba(0,0,0,0.1) 60%,transparent 100%)",
                    }}/>
                    <span style={{
                      position:"absolute",top:14,left:14,
                      background:c.accent,color:"white",
                      fontSize:10,fontWeight:800,
                      borderRadius:6,padding:"3px 9px",
                      letterSpacing:"0.06em",textTransform:"uppercase",
                    }}>{c.tag}</span>
                  </div>

                  <div style={{padding:"16px 18px 18px",background:"white"}}>
                    <h3 style={{fontFamily:"var(--serif)",fontSize:"1.15rem",fontWeight:400,color:"var(--ink)",marginBottom:4,letterSpacing:"-0.01em"}}>{c.heading}</h3>
                    <p style={{fontSize:12.5,color:"var(--ink-60)",lineHeight:1.5,marginBottom:12}}>{c.sub}</p>
                    <button style={{
                      background:"var(--ink)",color:"white",border:"none",
                      borderRadius:8,padding:"9px 18px",
                      fontFamily:"var(--sans)",fontWeight:600,fontSize:12,
                      cursor:"pointer",transition:"all 0.18s",letterSpacing:"0.02em",
                    }}
                      onMouseEnter={e => e.currentTarget.style.background="#f97316"}
                      onMouseLeave={e => e.currentTarget.style.background="var(--ink)"}
                    >{c.cta} →</button>
                  </div>
                </div>
              ))}
            </div>
          </section>

          {/* ── Stats Bar ── */}
          <div style={{
            background:"linear-gradient(135deg,var(--ink) 0%,#1c1410 100%)",
            borderRadius:18,padding:"2.2rem 2.5rem",
            display:"grid",gridTemplateColumns:"repeat(4,1fr)",
            gap:"1.5rem",marginBottom:"2.5rem",
            boxShadow:"var(--shadow-lg)",
          }}>
            {stats.map((s, i) => (
              <div key={i} style={{textAlign:"center"}}>
                <div style={{fontFamily:"var(--serif)",fontSize:"2rem",fontWeight:400,color:"white",marginBottom:4,letterSpacing:"-0.02em"}}>{s.value}</div>
                <div style={{fontSize:12,color:"rgba(255,255,255,0.5)",letterSpacing:"0.04em",textTransform:"uppercase"}}>{s.label}</div>
              </div>
            ))}
          </div>

          {/* ── Newsletter / CTA ── */}
          <div style={{
            background:"var(--orange-pale)",
            border:"1px solid #fed7aa",
            borderRadius:18,
            padding:"2.5rem 3rem",
            display:"flex",alignItems:"center",justifyContent:"space-between",
            gap:"2rem",flexWrap:"wrap",
          }}>
            <div style={{display:"flex",alignItems:"flex-start",gap:16}}>
              <div style={{width:48,height:48,borderRadius:14,background:"linear-gradient(135deg,#f97316,#ea580c)",display:"flex",alignItems:"center",justifyContent:"center",flexShrink:0,boxShadow:"0 4px 14px rgba(249,115,22,0.35)"}}>
                <MailIcon size={22} stroke="white" strokeWidth={1.8} />
              </div>
              <div>
                <h2 style={{fontFamily:"var(--serif)",fontSize:"1.5rem",fontWeight:400,color:"var(--ink)",marginBottom:6,letterSpacing:"-0.02em"}}>
                  Stay ahead of the deals
                </h2>
                <p style={{fontSize:13.5,color:"var(--ink-60)",lineHeight:1.6,maxWidth:380}}>
                  Get exclusive offers, early access to sales, and curated picks delivered straight to your inbox.
                </p>
              </div>
            </div>
            <div style={{display:"flex",gap:10,flexWrap:"wrap"}}>
              <input
                placeholder="Your email address"
                style={{
                  padding:"11px 16px",
                  border:"1.5px solid #fdba74",
                  borderRadius:10,fontSize:13,
                  outline:"none",fontFamily:"var(--sans)",
                  background:"white",minWidth:230,
                  color:"var(--ink)",
                }}
                onFocus={e => e.target.style.borderColor="#f97316"}
                onBlur={e => e.target.style.borderColor="#fdba74"}
              />
              <button style={{
                background:"linear-gradient(135deg,#f97316,#ea580c)",
                color:"white",border:"none",
                borderRadius:10,padding:"11px 22px",
                fontFamily:"var(--sans)",fontWeight:700,fontSize:13,
                cursor:"pointer",transition:"all 0.2s",
                boxShadow:"0 4px 14px rgba(249,115,22,0.35)",
                letterSpacing:"0.02em",
              }}
                onMouseEnter={e => e.currentTarget.style.opacity="0.88"}
                onMouseLeave={e => e.currentTarget.style.opacity="1"}
              >Subscribe →</button>
            </div>
          </div>

        </main>

        {/* ══════════ FOOTER ══════════ */}
        <footer style={{background:"var(--ink)",padding:"3rem 2rem 1.8rem",marginTop:"1rem"}}>
          <div style={{maxWidth:1340,margin:"0 auto",display:"flex",justifyContent:"space-between",gap:"2.5rem",flexWrap:"wrap",marginBottom:"2rem"}}>
            {/* Brand */}
            <div style={{maxWidth:240}}>
              <div style={{display:"flex",alignItems:"center",gap:9,marginBottom:14}}>
                <div style={{width:32,height:32,borderRadius:9,background:"linear-gradient(135deg,#f97316,#ea580c)",display:"flex",alignItems:"center",justifyContent:"center"}}>
                  <ShoppingBagIcon size={15} stroke="white" strokeWidth={2.3} />
                </div>
                <span style={{fontFamily:"var(--serif)",fontSize:"1.15rem",fontWeight:400,color:"white",letterSpacing:"-0.01em"}}>InstaBuy</span>
              </div>
              <p style={{fontSize:12.5,color:"rgba(255,255,255,0.4)",lineHeight:1.7}}>
                Your trusted shopping destination for quality products at the best prices. Made with ❤️ in India.
              </p>
              <div style={{display:"flex",gap:10,marginTop:16}}>
                {["f","in","t"].map((letter, i) => (
                  <div key={i} className="social-btn" style={{cursor:"pointer",transition:"opacity 0.18s"}}>
                    <SocialIcon letter={letter} />
                  </div>
                ))}
              </div>
            </div>

            {/* Links */}
            <div style={{display:"flex",gap:"3rem",flexWrap:"wrap"}}>
              {Object.entries(menuItems).map(([cat, items]) => (
                <div key={cat}>
                  <p style={{fontSize:10,fontWeight:700,textTransform:"uppercase",letterSpacing:"0.1em",color:"rgba(255,255,255,0.3)",marginBottom:12}}>{cat}</p>
                  {items.map(item => (
                    <a key={item.name} href={item.href} className="ft-link"
                      style={{display:"block",fontSize:12.5,color:"rgba(255,255,255,0.55)",textDecoration:"none",marginBottom:8,transition:"color 0.18s",lineHeight:1.4}}>
                      {item.name}
                    </a>
                  ))}
                </div>
              ))}
            </div>
          </div>

          <div style={{
            borderTop:"1px solid rgba(255,255,255,0.07)",
            paddingTop:"1.2rem",
            display:"flex",justifyContent:"space-between",alignItems:"center",
            flexWrap:"wrap",gap:8,
          }}>
            <p style={{fontSize:11.5,color:"rgba(255,255,255,0.25)"}}>© 2026 InstaBuy. All rights reserved.</p>
            <div style={{display:"flex",gap:16}}>
              {["Privacy","Terms","Cookies"].map(l => (
                <a key={l} href={`/${l.toLowerCase()}`} className="ft-link"
                  style={{fontSize:11.5,color:"rgba(255,255,255,0.25)",textDecoration:"none",transition:"color 0.18s"}}>
                  {l}
                </a>
              ))}
            </div>
          </div>
        </footer>

      </div>
    </>
  );
}
